Node* deleteAllOccurrences(Node* head, int X) {
    Node* curr = head;

    while (curr != NULL) {
        if (curr->data == X) {

            if (curr == head) {
                head = curr->next;
                if (head != NULL) head->prev = NULL;

            } else {
                curr->prev->next = curr->next;
                if (curr->next != NULL)
                    curr->next->prev = curr->prev;
            }
        }
        curr = curr->next;
    }
    return head;
}

