function deleteAllOccurrences(head, X) {
    let curr = head;

    while (curr) {
        if (curr.data === X) {

            // If it's the head node
            if (curr === head) {
                head = curr.next;
                if (head) head.prev = null;

            } else {
                if (curr.prev) curr.prev.next = curr.next;
                if (curr.next) curr.next.prev = curr.prev;
            }
